parameters.item/hso_flowerror:
Projektleitung: @{coalesce(outputs('Get_Quote')?['body/sst_projektleitung_id/azureactivedirectoryobjectid'], 'fehlt')}
Vertrieb: @{if(
	empty(body('Get_Sales_Responsible_from_Quote')?['systemuser_bookableresource_UserId']),
	'fehlt', 
	if(
		empty(body('Get_Sales_Responsible_from_Quote')?['systemuser_bookableresource_UserId'][0]?['sst_personnelnumber_str']),
		'fehlt',
		body('Get_Sales_Responsible_from_Quote')?['systemuser_bookableresource_UserId'][0]?['sst_personnelnumber_str']
	)
)}
Standort: @{coalesce(outputs('Get_Quote')?['body/msdyn_defaultshippingsite/msdyn_siteid'], 'fehlt')}
Lagerort: @{coalesce(outputs('Get_Quote')?['body/msdyn_defaultshippingwarehouse/msdyn_warehouseidentifier'], 'fehlt')}
Rechnungsadresse: @{if(empty(outputs('Get_Quote')?['body/customerid_account/sst_adresse2_locationid']), 'fehlt', 'vorhanden')}
Lieferadresse: @{if(empty(variables('varQuoteDeliveryAddress')), 'fehlt', 'vorhanden')}

Compose_Project_Start_Date.inputs:
@if(
  or(
    equals(
      dayOfWeek(utcNow()),
      0
    ), 
    equals(
      dayOfWeek(utcNow()),
      6
    )
  ),
  addDays(
    utcNow(), 
    if(
      equals(
        dayOfWeek(utcNow()),
        0
      ),
      1,
      2
    )
  ),
  utcNow()
)

